// ---- Interval helpers (1D coverage along a wall line) ----
type Interval = [number, number];

function mergeIntervals(arr: Interval[]): Interval[] {
  if (arr.length === 0) return [];
  const s = arr.map((i) => [...i] as Interval).sort((a, b) => a[0] - b[0]);
  const out: Interval[] = [[...s[0]] as Interval];
  for (let i = 1; i < s.length; i++) {
    const last = out[out.length - 1];
    if (s[i][0] <= last[1] + 1e-6) last[1] = Math.max(last[1], s[i][1]);
    else out.push([...s[i]] as Interval);
  }
  return out;
}

function subtractGaps(intervals: Interval[], gaps: Interval[]): Interval[] {
  let result = intervals.map((i) => [...i] as Interval);
  for (const g of gaps) {
    const next: Interval[] = [];
    for (const [a, b] of result) {
      if (g[1] <= a || g[0] >= b) {
        next.push([a, b]);
        continue;
      }
      if (g[0] > a) next.push([a, g[0]]);
      if (g[1] < b) next.push([g[1], b]);
    }
    result = next;
  }
  return result.filter(([a, b]) => b - a > 0.05);
}

/** Shared boundary line between two world rects (for carving door gaps). */
function sharedEdge(
  a: Rect,
  b: Rect,
): { axis: "v" | "h"; line: number; span: Interval } | null {
  const eps = 0.02;
  for (const [ax, bx] of [
    [a.x2, b.x1],
    [a.x1, b.x2],
  ]) {
    if (Math.abs(ax - bx) < eps) {
      const z1 = Math.max(a.z1, b.z1);
      const z2 = Math.min(a.z2, b.z2);
      if (z2 - z1 > 0.5) return { axis: "v", line: ax, span: [z1, z2] };
    }
  }
  for (const [az, bz] of [
    [a.z2, b.z1],
    [a.z1, b.z2],
  ]) {
    if (Math.abs(az - bz) < eps) {
      const x1 = Math.max(a.x1, b.x1);
      const x2 = Math.min(a.x2, b.x2);
      if (x2 - x1 > 0.5) return { axis: "h", line: az, span: [x1, x2] };
    }
  }
  return null;
}

const key = (n: number) => n.toFixed(2);

function generateWalls(): { walls: MapBox[]; doors: DoorGap[] } {
  const doors: DoorGap[] = [];
  // Coverage: every room edge becomes a wall line; shared edges merge into one.
  const vCover = new Map<string, Interval[]>();
  const hCover = new Map<string, Interval[]>();
  const vGap = new Map<string, Interval[]>();
  const hGap = new Map<string, Interval[]>();
  const push = (m: Map<string, Interval[]>, k: string, iv: Interval) => {
    const a = m.get(k);
    if (a) a.push(iv);
    else m.set(k, [iv]);
  };

  for (const r of ROOMS.values()) {
    if (r.id === "lighting_booth") continue; // elevated, built separately
    push(vCover, key(r.x1), [r.z1, r.z2]);
    push(vCover, key(r.x2), [r.z1, r.z2]);
    push(hCover, key(r.z1), [r.x1, r.x2]);
    push(hCover, key(r.z2), [r.x1, r.x2]);
  }

  // Carve door gaps. Multiple doors between the same pair are spread along the edge.
  const pairCount = new Map<string, number>();
  const pairSeen = new Map<string, number>();
  for (const [a, b] of DOORS) {
    const pk = [a, b].sort().join("|");
    pairCount.set(pk, (pairCount.get(pk) ?? 0) + 1);
  }
  for (const [aId, bId] of DOORS) {
    const a = ROOMS.get(aId);
    const b = ROOMS.get(bId);
    if (!a || !b) continue;
    const edge = sharedEdge(a, b);
    if (!edge) continue;
    const pk = [aId, bId].sort().join("|");
    const total = pairCount.get(pk) ?? 1;
    const idx = pairSeen.get(pk) ?? 0;
    pairSeen.set(pk, idx + 1);

    const [s1, s2] = edge.span;
    const frac = (idx + 1) / (total + 1);
    let c = s1 + (s2 - s1) * frac;
    c = Math.min(s2 - DOOR_W / 2 - 0.2, Math.max(s1 + DOOR_W / 2 + 0.2, c));
    const gap: Interval = [c - DOOR_W / 2, c + DOOR_W / 2];
    push(edge.axis === "v" ? vGap : hGap, key(edge.line), gap);
    doors.push({
      id: `door${doors.length}`,
      axis: edge.axis,
      line: edge.line,
      center: c,
      width: DOOR_W,
      rooms: [aId, bId],
    });
  }

  // Front doors gap (lobby south exterior). Barred collider added separately.
  push(hGap, key(wz(52)), [wx(35) - DOOR_W / 2, wx(35) + DOOR_W / 2]);

  const walls: MapBox[] = [];
  for (const [k, ivs] of vCover) {
    const x = parseFloat(k);
    for (const [z1, z2] of subtractGaps(mergeIntervals(ivs), vGap.get(k) ?? [])) {
      walls.push({ x, y: H / 2, z: (z1 + z2) / 2, w: T, h: H, d: z2 - z1, color: COL_WALL });
    }
  }
  for (const [k, ivs] of hCover) {
    const z = parseFloat(k);
    for (const [x1, x2] of subtractGaps(mergeIntervals(ivs), hGap.get(k) ?? [])) {
      walls.push({ x: (x1 + x2) / 2, y: H / 2, z, w: x2 - x1, h: H, d: T, color: COL_WALL });
    }
  }
  return { walls, doors };
}

/** A lockable doorway opening (the Caretaker can slam it shut). */
export interface DoorGap {
  id: string;
  axis: "v" | "h"; // vertical wall line (x=line) or horizontal (z=line)
  line: number;
  center: number;
  width: number;
  rooms: [string, string]; // the two rooms this doorway connects
}

/** Collider box that fills a door opening when it's locked. */
export function doorBox(d: DoorGap): MapBox {
  return d.axis === "v"
    ? { x: d.line, y: H / 2, z: d.center, w: T, h: H, d: d.width, color: 0x6b5a2a }
    : { x: d.center, y: H / 2, z: d.line, w: d.width, h: H, d: T, color: 0x6b5a2a };
}

// ---- Cover blocks (deterministic placement within cover zones) ----
const COVER_ZONES_JSON: Array<[number, number, number, number]> = [
  [47, 35, 63, 51], // gym
  [25, 20, 45, 35], // theatre bleachers
  [3, 14, 19, 33], // dressing racks
  [47, 14, 63, 23], // workshop benches
  [3, 2, 25, 7], // green room shelves
];
function generateCover(): MapBox[] {
  const out: MapBox[] = [];
  const fracs: Array<[number, number, number]> = [
    [0.3, 0.35, 1.4],
    [0.65, 0.6, 1.2],
    [0.45, 0.8, 1.0],
  ];
  for (const [x1, z1, x2, z2] of COVER_ZONES_JSON) {
    for (const [fx, fz, s] of fracs) {
      const x = wx(x1 + (x2 - x1) * fx);
      const z = wz(z1 + (z2 - z1) * fz);
      out.push({ x, y: s / 2, z, w: s, h: s, d: s, color: COL_COVER });
    }
  }
  return out;
}

