function generateLockers(): LockerDef[] {
  return HIDING_JSON.map(([type, , x, z], i) => {
    const px = wx(x);
    const pz = wz(z);
    // Face toward the building center so you "look out" into the room.
    const ry = Math.atan2(-(0 - px), -(0 - pz));
    return { id: `hide${i + 1}`, type, x: px, z: pz, ry };
  });
}

